'use client';

/**
 * Web Vitals Reporter — client component that observes Core Web Vitals
 * and reports them to the console (development) or monitoring endpoint (production).
 *
 * Add to root layout:
 *   <WebVitalsReporter />
 *
 * In production, metrics are sent to /api/metrics/vitals (non-blocking).
 *
 * @module components/monitoring/web-vitals-reporter
 */

import { useEffect, useRef } from 'react';
import {
  observeAllVitals,
  type WebVitalMetric,
  type WebVitalName,
} from '@/lib/performance/web-vitals';

// ---------------------------------------------------------------------------
// Pure helpers (exported for testing)
// ---------------------------------------------------------------------------

/**
 * Build a structured log line from a metric.
 */
export function formatVitalLog(metric: WebVitalMetric): string {
  const val = metric.name === 'CLS' ? metric.value.toFixed(3) : `${Math.round(metric.value)}ms`;
  return `[Web Vital] ${metric.name}: ${val} (${metric.rating})`;
}

/**
 * Check if a metric is actionable (needs-improvement or poor).
 */
export function isActionable(metric: WebVitalMetric): boolean {
  return metric.rating !== 'good';
}

/**
 * Build the payload for the metrics reporting endpoint.
 */
export function buildReportPayload(
  metrics: WebVitalMetric[],
  pathname: string,
): Record<string, unknown> {
  return {
    pathname,
    metrics: metrics.map((m) => ({
      name: m.name,
      value: m.value,
      rating: m.rating,
      navigationType: m.navigationType,
      timestamp: m.timestamp,
    })),
    userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'unknown',
    timestamp: Date.now(),
  };
}

/**
 * Batch size for sending metrics in one request.
 */
export const BATCH_SIZE = 5;

/**
 * Returns the count of unique metric names in a list.
 */
export function uniqueMetricCount(metrics: WebVitalMetric[]): number {
  const names = new Set<WebVitalName>();
  for (const m of metrics) {
    names.add(m.name);
  }
  return names.size;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export default function WebVitalsReporter() {
  const metricsRef = useRef<WebVitalMetric[]>([]);
  const sentRef = useRef(false);

  useEffect(() => {
    const isDev = process.env.NODE_ENV === 'development';
    const pathname = typeof window !== 'undefined' ? window.location.pathname : '/';

    const handleMetric = (metric: WebVitalMetric) => {
      // Log in development
      if (isDev) {
        // eslint-disable-next-line no-console
        console.log(formatVitalLog(metric));
      }

      metricsRef.current.push(metric);

      // In production, batch-send once we have enough metrics
      if (!isDev && !sentRef.current && uniqueMetricCount(metricsRef.current) >= BATCH_SIZE) {
        sentRef.current = true;
        const payload = buildReportPayload(metricsRef.current, pathname);

        // Non-blocking beacon send
        if (typeof navigator !== 'undefined' && navigator.sendBeacon) {
          navigator.sendBeacon('/api/metrics/vitals', JSON.stringify(payload));
        } else {
          fetch('/api/metrics/vitals', {
            method: 'POST',
            body: JSON.stringify(payload),
            headers: { 'Content-Type': 'application/json' },
            keepalive: true,
          }).catch(() => {
            // Silently ignore — monitoring should never break the app
          });
        }
      }
    };

    const cleanup = observeAllVitals(handleMetric);
    return cleanup;
  }, []);

  // This component renders nothing — it only observes
  return null;
}
